/************************************
 * Set urls of parent case documents 
 * 
 * by Cinthia Romero
 * modified by Adriana Centellas
 ***********************************/

// Get current URL
var currentUrl = window.location.href;
var environmentUrl = currentUrl.split("/")[0];
var parentRequestID = this._request.id;
var documentsUrl = {};

// Function to generate download links if files exist
function getDocumentLinks(fileArray, environmentUrl, parentRequestID) {
    if (Array.isArray(fileArray)) {
        return fileArray.map(fileObj => 
            "<p><a class='btn btn-link' draggable='false' href='" + environmentUrl + "/request/" + parentRequestID + "/files/" + fileObj.file + "' download=''>Download</a></p>"
        ).join("<br>");
    } else if (fileArray != null && typeof fileArray === 'object' && fileArray.file) {
        return "<p><a class='btn btn-link' draggable='false' href='" + environmentUrl + "/request/" + parentRequestID + "/files/" + fileArray.file + "' download=''>Download</a></p>";
    } else {
        // Fallback in case it's a single ID or invalid format
        return "<p><a class='btn btn-link' draggable='false' href='" + environmentUrl + "/request/" + parentRequestID + "/files/" + fileArray + "' download=''>Download</a></p>";
    }
}

// Validate and generate links for each document type

if (
    (Array.isArray(this.PE_UPLOAD_IC_PRESENTATION) && this.PE_UPLOAD_IC_PRESENTATION.length > 0) ||
    (!Array.isArray(this.PE_UPLOAD_IC_PRESENTATION) && this.PE_UPLOAD_IC_PRESENTATION != null)
) {
    return getDocumentLinks(this.PE_UPLOAD_IC_PRESENTATION, environmentUrl, parentRequestID);
}

